<template>
  <div class="cart-container">
<Navbar />
    <div class="main-wrapper">
    <Spinner v-if="isLoading === true" />

    <div v-else>
      <div class="cart-alert" v-if="carts.length === 0">
      <h2>您的購物車沒有商品！</h2>
      <router-link to="/products">
        <div class="shopping-btn">前往購物</div>
      </router-link>
    </div>

    <div class="main-container mt-5" v-else>
      <Stepper :stepper="stepper" />
      <div class="cart-wrapper">
        <CartListItem :cartListItems="cartItems" :stepper="stepper"
        @delete-cartItem="handleDelete"
        />

        <SubTotal
          :initial-stepper="stepper"
          :totalPrice="totalPrice"
          @click-step-btn="handleStepBtn"
        />

        <CheckoutForm
          :initial-stepper="stepper"
          :totalPrice="totalPrice"
          :cartId="cartId"
          @click-step-btn="handleStepBtn"
          @get-order-id="getOrderId"
        />
        <div class="completed-wrapper"
        v-if="stepper===3"
        >
          <div class="img-wrapper">
            <img
              class="completed-img"
              src="../../public/photo/completed.png"
              alt=""
            />
          </div>
          <h1>感謝您的訂購</h1>
          <p>已收到您的訂單，請您檢視訂單並確認付款狀態</p>
          <div class="btn-wrapper">
            <router-link to="/home">
              <div class="prev-btn">前往首頁</div>
            </router-link>
            <router-link to="/order">
              <div class="next-btn">查看訂單</div>
            </router-link>
          </div>
        </div>
      </div>
    </div>

    </div>
    
  </div>

  </div>
 
</template>

<script>
import Stepper from "../components/Stepper.vue";
import CartListItem from "../components/CartListItem.vue";
import SubTotal from "../components/subTotal.vue";
import CheckoutForm from "../components/CheckoutForm.vue";
import CartApi from "../apis/cart";
import OrderApi from "../apis/order";
import { mapState } from "vuex";
import { Toast } from "../utils/helpers";
import Spinner from "../components/Spinner.vue";
import Navbar from "../components/Navbar.vue";

export default {
  components: {
    Stepper,
    CartListItem,
    SubTotal,
    CheckoutForm,
    Spinner,
    Navbar
  },
  data() {
    return {
      cartId: 0,
      carts: [],
      cartItems: [],
      stepper: 1,
      orderId: "",
      isLoading: true
    };
  },
  created() {
    this.fetchCartListItems();
  },
  methods: {
    async fetchCartListItems() {
      try {
        const cartId = localStorage.getItem("cartId");

        const response = await CartApi.getCart({
          cartId: cartId,
        });
        const { data } = response

       if(response.status === 'error') {
        throw new Error (data.message)
       }
        this.$bus.$emit('cartUpdate', {
            cart: data.carts
          })
        this.carts = data.carts;
        this.carts.forEach((item) => {
          this.cartItems.push(item.cartProducts);
        });
        this.isLoading = false
      } catch (error) {
        this.isLoading = false
        if(this.isAuthenticated === false) {
          Toast.fire({
          icon: 'error',
          title: '請先登入使用者'
        })
        } else {
          Toast.fire({
          icon: 'error',
          title: '無法取得購物車資料，請稍後再試'
        })
        }
        
        console.log(error);
      }
    },
    handleStepBtn(stepper) {
      this.stepper = stepper;
    },
    async handleSubmit() {
      try {
        const response = await OrderApi.postOrder();
        console.log("response", response);
      } catch (error) {
        console.log(error);
      }
      if (this.stepper > 1) {
        this.stepper++;
      }
      const data = JSON.stringify({
        name: this.name,
        email: this.email,
        phone: this.phone,
        address: this.address,
      });
      console.log("data", data);
    },
    getOrderId(gotOrderId) {
      this.orderId = gotOrderId;
    },
    handleDelete(cartItem) {
      console.log('12355',cartItem)
  const result = this.carts.filter(item => item.cartProducts !== cartItem)
  this.carts = result
  this.$bus.$emit('cartUpdate', {
            cart: result
          })

      
    }
  },
  computed: {
    totalPrice() {
      let total = 0;
      this.cartItems.forEach((item) => {
        total += item.CartItem.quantity * item.price;
      });
      return total;
    },
    ...mapState(["currentUser", "isAuthenticated"]),
  },
};
</script>

<style lang="scss">
.cart-alert {
  h2 {
    margin: 6rem auto 3rem;
  }
  .shopping-btn {
    margin: 0 auto;
    padding: 0.5rem 0;
    width: 8rem;
    border-radius: 0;
    background: #00457c;
    color: #ffffff;
  }
}
.main-container {
  margin: 1rem auto;
  padding-top: 3rem;

  @media (min-width: 768px) {
    padding-top: 0;
  }
}
.cart-wrapper {
  @media (min-width: 800px) {
    display: flex;
  }
  @media (min-width: 1100px) {
    margin: 0 10%;
  }
}

.completed-wrapper {
  width: 90%;
  margin: 10rem 5%;
  .img-wrapper {
    height: 10rem;
    width: 10rem;
    margin: 3rem auto;
    @media (min-width: 768px) {
      height: 15rem;
    width: 15rem;

    }
    
    
  }
  h1 {
    font-weight: 700;
    margin: 2rem;
  }
  p {
    font-size: 1.5rem;
  }
  .btn-wrapper {
    display: flex;
    justify-content: center;
    .prev-btn {
      border: 1px solid #747373;
      margin: 1rem 1.5rem;
      padding: 0.5rem 1rem;
      color: #2a2a2a;
      border-radius: 5px;

      &:hover {
        opacity: 0.7;
      }
    }
    .next-btn {
      border: 1px solid #747373;
      margin: 1rem 1.5rem;
      padding: 0.5rem 1rem;
      color: #ffffff;
      background-color: #00457c;
      border-radius: 5px;
      &:hover {
        opacity: 0.7;
      }
    }
  }
}
</style>