<template>
  <div class="signin-container">
    <Navbar />
    <div class="wrapper py-5">
      <Spinner v-if="isLoading === true" />
      <div class="title-wrapper text-center mb-4 d-flex justify-content-center">
        <ProcessSpinner v-if="isProcessing === true" />
        <div class="title-login" :class="{ selected: loginSelected }" @click.prevent.stop="loginSelect">
          會員登入
        </div>
        <span class="line"></span>
        <div class="title-register" :class="{ selected: registerSelected }" @click.prevent.stop="registerSelect">
          立即註冊
        </div>
      </div>
      <form class="w-40" v-if="loginSelected" @submit.prevent.stop="loginSubmit">

        <div class="login-wrapper">
          <div class="form-label-group mb-2">
            <label for="email" hidden>email</label>
            <input v-model="email" id="email" name="email" type="email" class="form-control" placeholder="請輸入 Email"
              required />
          </div>
          <div class="form-label-group mb-3">
            <label for="password" hidden>Password</label>
            <input v-model="password" id="password" name="password" type="password" class="form-control"
              placeholder="請輸入密碼" required />
          </div>
          <button class="btn btn-lg btn-primary btn-block mb-3" type="submit" v-if="loginSelected">
            會員登入
          </button>
          <button class="fb-login" @click.stop.prevent="fbLogin">
            <img src="../../public/photo/2021_Facebook_icon.svg.webp" alt="" style="width: 1.5rem; height:1.5rem;">
            <div>Facebook 登入</div></button>

        </div>
      </form>

      <form class="w-40" v-if="registerSelected" @submit.prevent.stop="registerSubmit">
        <div class="login-wrapper">

          <div class="form-label-group mb-2">
            <label for="name" hidden>Name</label>
            <input v-model="name" id="name" name="name" type="text" class="form-control" placeholder="請輸入名字" required />
          </div>
          <div class="form-label-group mb-2">
            <label for="email" hidden>email</label>
            <input v-model="email" id="email" name="email" type="email" class="form-control" placeholder="請輸入 Email"
              required />
          </div>
          <div class="form-label-group mb-3">
            <label for="password" hidden>Password</label>
            <input v-model="password" id="password" name="password" type="password" class="form-control"
              placeholder="請輸入密碼" required />
          </div>
          <div class="form-label-group mb-3">
            <label for="confirmPassword" hidden>Password Check</label>
            <input v-model="confirmPassword" id="confirmPassword" name="confirmPassword" type="password"
              class="form-control" placeholder="請再一次輸入密碼" required />
          </div>
          <button class="btn btn-lg btn-primary btn-block mb-3" type="submit">
            立即註冊
          </button>
        </div>
      </form>
    </div>
  </div>
</template>

<script>
import authorizationAPI from "../apis/authorization";
import { Toast } from "./../utils/helpers";
import ProcessSpinner from "../components/ProcessSpinner.vue";
import Spinner from "../components/Spinner.vue";
import Navbar from "../components/Navbar.vue";
import store from "../store/index"

export default {
  components: {
    ProcessSpinner,
    Spinner,
    Navbar
  },
  data() {
    return {
      name: "",
      email: "",
      password: "",
      confirmPassword: "",
      loginSelected: true,
      registerSelected: false,
      isProcessing: false,
      isLoading: false
    };
  },
  created() {

  },
  methods: {
    async loginSubmit() {
      try {
        this.isLoading = true
        if (!this.email || !this.password) {
          Toast.fire({
            icon: "warning",
            title: "請填入所有欄位",
          });
          return;
        }

        const response = await authorizationAPI.signIn({
          email: this.email,
          password: this.password,
        });
        const { data } = response;

        if (data.status === "error") {
          throw new Error(data.message);
        }
        localStorage.setItem("token", data.token);

        this.$store.commit('setCurrentUser', data.user)
        if (data.user.role === 'admin') {
          this.$router.push("/admin/products")
        } else {
          this.$router.push("/products")
        }
      } catch (error) {
        this.isLoading = false
        this.password = "";
        Toast.fire({
          icon: "warning",
          title: error.message,
        });
        console.log(error);
      }
    },
    async registerSubmit() {
      try {
        this.isProcessing = true
        if (
          !this.name ||
          !this.email ||
          !this.password ||
          !this.confirmPassword
        ) {
          Toast.fire({
            icon: "warning",
            title: "請填入所有欄位",
          });
          return;
        }

        const response = await authorizationAPI.signUp({
          name: this.name,
          email: this.email,
          password: this.password,
          confirmPassword: this.confirmPassword,
        });
        const { data } = response;
        if (data.status === "error") {
          throw new Error(data.message);
        }
        localStorage.setItem("token", data.token);
        this.$router.go(0);
        this.isProcessing = false

      } catch (error) {
        this.isProcessing = false
        Toast.fire({
          icon: "warning",
          title: error.message,
        });
        console.log(error);
      }
    },
    fbLogin() {
      window.FB.getLoginStatus((response) => {
        if (response.status === 'connected') {
          window.FB.api(
            "/me",
            { fields: "name , email" },
            async function (response) {
              await store.dispatch("fetchFbUser", response)
            })
        } else {
          window.FB.login(
            function (response) {
              if (response.status === "connected") {
                window.FB.api(
                  "/me",
                  { fields: "name, email" },
                  async function (response) {
                    await store.dispatch("fetchFbUser", response)
                  }
                )
              } else {
                console.log('Login Failure')
              }
            },
            {
              scope: "email, public_profile",
              return_scopes: true,
            }
          )
        }
      });
    },
    registerSelect() {
      if (this.registerSelected === false) {
        this.loginSelected = false;
        this.registerSelected = true;
      }
    },
    loginSelect() {
      if (this.loginSelected === false) {
        this.loginSelected = true;
        this.registerSelected = false;

      }
    },
  },
};
</script>

<style lang="scss">
.wrapper {
  display: block;
  justify-content: center;
  position: relative;

  .title-wrapper {
    margin: auto 20%;
    text-align: center;

    @media (min-width: 900px) {
      margin: auto 30%;
    }

    .line {
      background: #747373;
      width: 1px;
      content: "";
    }

    .title-login,
    .title-register {
      width: 10rem;
      margin: auto;
      font-size: 1.5rem;
      font-weight: 550;
    }

    .selected {
      color: red;
    }
  }

  .login-wrapper {
    margin: auto 20%;

    @media (min-width: 900px) {
      margin: auto 30%;
    }
  }
  .fb-login {
    display: flex;
    justify-content: center;
    align-items: center;
   height: 2.5rem;
    width: 100%;
    margin: auto;
    border-radius: 3px;
    border: 1px solid #747373;
    img{
      margin-right: 1.5rem;
    }
  }
}
</style>