<template>
  <div class="search-container">
    <Navbar />
    <Spinner 
    v-if="isLoading === true"
    />
    <div
    class="products-wrapper"
    v-else
    >
    
        <div class="side-wrapper">
          <div class="title">商品分類</div>
          <div class="list-item" @click="$router.push('/products')">
            <i class="fas fa-angle-left"></i>
            <span> 所有分類</span>
          </div>
        </div>
        <div class="main-wrapper">
          <div class="title">
            找到{{ number }}件"{{ `${$route.query.key}` }}"的商品
          </div>
          <div class="cards-wrapper">
            <div
              class="product-card"
              v-for="product in products"
              :key="product.id"
            >
              <router-link
                :to="{ name: 'product', params: { id: product.id } }"
              >
                <div class="product-img">
                  <img :src="product.image" alt="" />
                </div>
                <div class="product-name">{{ product.name }}</div>
                <div class="product-price">NT$ {{ product.price }}</div>
              </router-link>
            </div>
          </div>
        </div>
      </div>
    </div>
</template>

<script>
import ProductsApi from "../apis/products";
import Spinner from "../components/Spinner.vue";
import { Toast } from "../utils/helpers";
import Navbar from "../components/Navbar.vue";

export default {
  components: {
    Spinner,
    Navbar,
  },
  data() {
    return {
      products: [],
      number: "",
      isLoading: true,
    };
  },
  mounted() {
    console.log(this.$route.query.key);
    this.fetchProducts();
  },
  beforeRouteUpdate(to, from, next) {
    next();
    this.fetchProducts();
  },
  methods: {
    async fetchProducts() {
      try {
        const response = await ProductsApi.getProducts({
          categoryId: "",
          page: "",
          keyword: this.$route.query.key,
        });

        const { data } = response;
        if (response.status === "error") {
          throw new Error(data.message);
        }

        this.products = response.data.totalProducts;
        this.number = response.data.totalProducts.length;
        this.isLoading = false;
      } catch (error) {
        Toast.fire({
          icon: "error",
          title: "無法取得產品資料，請稍後再試",
        });
        console.log(error);
        this.isLoading = false;
      }
    },
  },
};
</script>
<style lang="scss">
.search-container {
  padding-top: 2rem;

@media (min-width: 768px) {
  padding-top: 0;
}
}

</style>